type CardProps = {
  variant: 'primary' | 'ghost';
  children: React.ReactNode;
};

export const Card = forwardRef<HTMLDivElement, CardProps>(({ variant, children }, ref) => {
  const baseClasses = 'rounded-lg p-5 mb-7';
  const variantClass = variant === 'primary'
    ? 'bg-[#3b82f6] text-white'
    : 'bg-opacity-50 bg-gray-100';

  return (
    <div ref={ref} className={`${baseClasses} ${variantClass}`}>
      {children}
    </div>
  );
});

